// Format appointment data for calendar event creation
const items = $input.all();
const formattedItems = [];

for (const item of items) {
  const data = item.json;

  // Parse appointment time
  const appointmentTime = new Date(data.appointment_time);

  // Calculate end time based on duration (default 60 minutes if not provided)
  const duration = data.duration || 60;
  const endTime = new Date(appointmentTime.getTime() + duration * 60000);

  // Create event summary and description from lead data
  const summary = `Appointment with ${data.lead_name || 'Lead'}`;
  const description = `
Lead: ${data.lead_name || 'N/A'}
Phone: ${data.phone || 'N/A'}
Email: ${data.email || 'N/A'}
Company: ${data.company || 'N/A'}
Qualification Score: ${data.qualification_score || 'N/A'}
Notes: ${data.notes || 'N/A'}
  `.trim();

  formattedItems.push({
    json: {
      ...data,
      start_time: appointmentTime.toISOString(),
      end_time: endTime.toISOString(),
      summary: summary,
      description: description,
      duration: duration
    }
  });
}

return formattedItems;

// Timezone-aware slot finder
const TIMEZONE = $('Workflow Configuration 3').first().json.TIMEZONE || 'Africa/Cairo';

function toLocalDate(isoStr, tz) {
  return new Date(new Date(isoStr).toLocaleString('en-US', { timeZone: tz }));
}
function toLocalNow(tz) {
  return new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
}

// Get calendar events from previous node
const events = $input.all();

// Get requested date and duration from webhook data
const requestedDate = $('Workflow Configuration 3').first().json.date || toLocalNow(TIMEZONE).toISOString().split('T')[0];
const durationMinutes = parseInt($('Workflow Configuration 3').first().json.duration) || 30;

// Define business hours
const businessStart = 9; // 9 AM
const businessEnd = 17; // 5 PM
const slotIncrement = 30; // 30 minutes

// Parse the requested date
const targetDate = toLocalDate(requestedDate + 'T00:00:00', TIMEZONE);
targetDate.setHours(0, 0, 0, 0);

// Create array of all possible time slots
const allSlots = [];
for (let hour = businessStart; hour < businessEnd; hour++) {
  for (let minute = 0; minute < 60; minute += slotIncrement) {
    const slotStart = new Date(targetDate);
    slotStart.setHours(hour, minute, 0, 0);

    const slotEnd = new Date(slotStart);
    slotEnd.setMinutes(slotEnd.getMinutes() + durationMinutes);

    // Only add if slot end is within business hours
    if (slotEnd.getHours() < businessEnd || (slotEnd.getHours() === businessEnd && slotEnd.getMinutes() === 0)) {
      allSlots.push({
        start_time: slotStart.toISOString(),
        end_time: slotEnd.toISOString()
      });
    }
  }
}

// Filter out slots that conflict with existing events
const availableSlots = allSlots.filter(slot => {
  const slotStart = new Date(slot.start_time);
  const slotEnd = new Date(slot.end_time);

  // Check if this slot conflicts with any existing event
  const hasConflict = events.some(item => {
    if (!item.json.start || !item.json.end) return false;

    const eventStart = new Date(item.json.start.dateTime || item.json.start.date);
    const eventEnd = new Date(item.json.end.dateTime || item.json.end.date);

    // Check for overlap
    return (slotStart < eventEnd && slotEnd > eventStart);
  });

  return !hasConflict;
});

// Return available slots
return [{
  json: {
    date: requestedDate,
    duration_minutes: durationMinutes,
    available_slots: availableSlots,
    total_available: availableSlots.length
  }
}];

const callId = $input.first().json.call_id;
const config = $('Set Configuration').first().json;

if (!callId) {
  throw new Error('No call_id from Retell: ' + JSON.stringify($input.first().json));
}

// Build SIP URI
const sipUri = `sip:${callId}@${config.RETELL_SIP_DOMAIN}`;

return [{ 
  json: { 
    callId,
    sipUri,
    toNumber: config.to_number,
    fromNumber: config.TWILIO_FROM_NUMBER,
    twilioAccountSid: config.TWILIO_ACCOUNT_SID
  } 
}];

