const responseText = $input.first().json?.message?.content || 
                       $input.first().json?.content?.[0]?.text || 
                       JSON.stringify($input.first().json);

const fallback = {
  qualification_status: 'not_qualified',
  score: 0,
  recommended_action: 'nurture',
  message: 'LLM response parse error — defaulting to not qualified',
  reasoning: ['Could not parse AI response'],
  collected_data: { project_type: '', project_scope: '', budget: '', timeline: '', location: '' }
};

try {
  // Strip markdown fences if present
  const cleaned = responseText.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  // Validate required fields
  const required = ['qualification_status', 'score', 'recommended_action'];
  const valid = required.every(k => parsed[k] !== undefined);

  if (!valid) {
    console.warn('LLM response missing required fields, using fallback');
    return [{ json: fallback }];
  }

  // Clamp score to 0-100
  parsed.score = Math.max(0, Math.min(100, Number(parsed.score) || 0));

  return [{ json: parsed }];
} catch (e) {
  console.error('LLM JSON parse failed:', e.message);
  return [{ json: fallback }];
}
